1	import { _decorator, Component, Enum, EventKeyboard, Input, input, KeyCode, Layout, log, Node, warn } from 'cc';
2	import { DEBUG } from 'cc/env';
3	import { eventManager } from 'db://astarte-framework/Managers';
4	import { Common } from '../Common/Common';
5	import { Symbol, IBountyData, GAME_EVENT } from '../Game_Define';
6	import { WantedPosterItem } from './WantedPosterItem';
7	const { ccclass, property } = _decorator;
8	
9	/**@ch 懸賞令排版方向設定（直/橫各一組）*/
10	@ccclass('WantedPosterLayoutConfig')
11	class WantedPosterLayoutConfig {
12	    @property({ type: Enum(Layout.Type), tooltip: "排版類型" })
13	    type = Layout.Type.VERTICAL;
14	
15	    @property({ type: Enum(Layout.ResizeMode), tooltip: "縮放模式" })
16	    resizeMode = Layout.ResizeMode.NONE;
17	
18	    @property({ tooltip: "左內距" }) paddingLeft: number = 0;
19	    @property({ tooltip: "右內距" }) paddingRight: number = 0;
20	    @property({ tooltip: "上內距" }) paddingTop: number = 0;
21	    @property({ tooltip: "下內距" }) paddingBottom: number = 0;
22	    @property({ tooltip: "水平間距" }) spacingX: number = 0;
23	    @property({ tooltip: "垂直間距" }) spacingY: number = 0;
24	    @property({ tooltip: "水平對齊（GRID 模式有效）" }) alignHorizontal: boolean = false;
25	    @property({ tooltip: "垂直對齊（GRID 模式有效）" }) alignVertical: boolean = false;
26	}
27	
28	/**@ch 懸賞令管理器事件*/
29	export const WANTED_POSTER_MANAGER_EVENT = {
30	    /**
31	     * @ch 設置懸賞令資料
32	     * @param IBountyData[] 懸賞令資料陣列
33	     */
34	    SET_WANTED_POSTER_DATA: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_DATA",
35	
36	    /**
37	     * @ch 設置懸賞令UI顯示狀態
38	     * @param isShow 是否顯示
39	     */
40	    SET_WANTED_POSTER_UI_SHOW: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_UI_SHOW",
41	
42	    /**
43	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark → Mark_Idle loop
44	     * @param baseSymbol number 對應的 BaseSymbol（M1~M9）
45	     * @param resolve () => void 播完 Mark 後呼叫（Mark_Idle 已在 spine 上 loop）
46	     */
47	    PLAY_MARK: "WANTED_POSTER_MANAGER_PLAY_MARK",
48	
49	    /**
50	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark_Active 並關閉 item
51	     * @param baseSymbol number 對應的 BaseSymbol
52	     * @param resolve () => void 播完 Mark_Active 且 item.active=false 後呼叫
53	     */
54	    PLAY_MARK_ACTIVE: "WANTED_POSTER_MANAGER_PLAY_MARK_ACTIVE",
55	    
56	    /**
57	     * @ch 遊戲介紹完成後顯示懸賞令x9999
58	     */
59	    GAME_INTRO_COMPLETE: "WANTED_POSTER_MANAGER_GAME_INTRO_COMPLETE",
60	}
61	
62	/**@ch 懸賞令管理器*/
63	@ccclass('WantedPosterManager')
64	export class WantedPosterManager extends Component {
65	    //#region Constants
66	    /**
67	     * @ch 需要註冊的事件列表
68	     */
69	    private static readonly EVENTS_TO_REGISTER = [
70	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
71	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
72	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
73	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
74	        WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE,
75	        GAME_EVENT.DEVICE_ROTATION,
76	    ];
77	
78	    /**
79	     * @ch GAME_INTRO_COMPLETE 顯示懸賞令的延遲（秒）
80	     * 補 intro spine 的 Wanted_On 幀事件偏早約 0.15 秒（暫時方案，待能改 spine 原檔後移除）
81	     */
82	    private static readonly GAME_INTRO_SHOW_DELAY = 0.15;
83	    //#endregion Constants
84	
85	    //#region Properties
86	    @property({
87	        type: Node,
88	        tooltip: "根節點"
89	    })
90	    private m_rootNode: Node = null;
91	
92	    @property({
93	        type: [WantedPosterItem],
94	        tooltip: "懸賞令物品"
95	    })
96	    private m_wantedPosterItems: WantedPosterItem[] = [];
97	
98	    @property({
99	        type: Layout,
100	        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
101	    })
102	    private m_layout: Layout = null;
103	
104	    @property({
105	        type: WantedPosterLayoutConfig,
106	        tooltip: "直向排版設定"
107	    })
108	    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
109	
110	    @property({
111	        type: WantedPosterLayoutConfig,
112	        tooltip: "橫向排版設定"
113	    })
114	    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
115	    //#endregion Properties
116	
117	    //#region Variables
118	    /**@ch 是否已初始化*/
119	    private m_isInitialized: boolean = false;
120	
121	    /**
122	     * @ch 各 item 目前綁定的懸賞令資料（null = 該 item 未顯示）
123	     * 與 m_wantedPosterItems 同索引，是「同 BaseSymbol 持續判斷」與「倍率是否變」的真實依據
124	     * （item 本身只記 BaseSymbol、不記 Multiple，故由 Manager 統一追蹤）
125	     */
126	    private m_currentBounty: (IBountyData | null)[] = [];
127	    //#endregion Variables
128	
129	    //#region Lifecycle
130	    /**@ch 元件載入時調用*/
131	    onLoad() {
132	        this.RegisterEvent();
133	        this.RegisterKeyboardEvents();
134	        this.EnsureCurrentBountySize();
135	    }
136	
137	    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
138	    start() {
139	        this.ApplyLayoutByOrientation();
140	    }
141	
142	    /**@ch 元件銷毀時調用*/
143	    onDestroy() {
144	        if (!this.m_isInitialized) return;
145	        this.UnregisterEvent();
146	        this.UnregisterKeyboardEvents();
147	        this.m_isInitialized = false;
148	    }
149	    //#endregion Lifecycle
150	
151	    //#region Event Management
152	    /**@ch 註冊鍵盤事件（測試用）*/
153	    private RegisterKeyboardEvents(): void {
154	        if (!DEBUG) return;
155	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
156	    }
157	
158	    /**@ch 取消註冊鍵盤事件（測試用）*/
159	    private UnregisterKeyboardEvents(): void {
160	        if (!DEBUG) return;
161	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
162	    }
163	
164	    /**@ch 註冊事件*/
165	    private RegisterEvent() {
166	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
167	            eventManager.Register(eventName, this);
168	        });
169	        this.m_isInitialized = true;
170	    }
171	
172	    /**@ch 取消註冊事件*/
173	    private UnregisterEvent() {
174	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
175	            eventManager.UnRegister(eventName, this);
176	        });
177	    }
178	
179	    /**
180	     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
181	     * @param args 事件參數
182	     * @returns 是否有效
183	     */
184	    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
185	        if (typeof args[0] !== 'boolean') {
186	            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
187	            return false;
188	        }
189	        return true;
190	    }
191	
192	    /**
193	     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
194	     * @param args 事件參數
195	     * @returns 是否有效
196	     */
197	    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
198	        if (!Array.isArray(args[0])) {
199	            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
200	            return false;
201	        }
202	        return true;
203	    }
204	
205	    /**
206	     * @ch 事件回調
207	     * @param event 事件名稱
208	     * @param args 事件參數
209	     */
210	    OnEvent(event: string, ...args: any[]) {
211	        switch (event) {
212	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
213	                if (this.ValidateSetWantedPosterDataArgs(args)) {
214	                    this.SetWantedPosterData(
215	                        args[0] as IBountyData[],
216	                        args[1] === true,
217	                        Array.isArray(args[2]) ? args[2] as number[] : undefined
218	                    );
219	                }
220	                break;
221	
222	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
223	                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
224	                    this.SetWantedPosterUIShow(args[0] as boolean);
225	                }
226	                break;
227	
228	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
229	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
230	                break;
231	
232	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
233	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
234	                break;
235	
236	            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
237	                this.HandleGameIntroComplete();
238	                break;
239	
240	            case GAME_EVENT.DEVICE_ROTATION:
241	                this.ApplyLayoutByOrientation();
242	                break;
243	
244	            default:
245	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
246	        }
247	    }
248	
249	    /**
250	     * @ch 依目前裝置方向套用對應的 Layout 設定
251	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
252	     */
253	    private ApplyLayoutByOrientation(): void {
254	        if (!this.m_layout) {
255	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
256	            return;
257	        }
258	        const isLandscape = Common.GetGameView().IsLandscape;
259	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
260	
261	        this.m_layout.type = cfg.type;
262	        this.m_layout.resizeMode = cfg.resizeMode;
263	        this.m_layout.paddingLeft = cfg.paddingLeft;
264	        this.m_layout.paddingRight = cfg.paddingRight;
265	        this.m_layout.paddingTop = cfg.paddingTop;
266	        this.m_layout.paddingBottom = cfg.paddingBottom;
267	        this.m_layout.spacingX = cfg.spacingX;
268	        this.m_layout.spacingY = cfg.spacingY;
269	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
270	        this.m_layout.alignVertical = cfg.alignVertical;
271	        this.m_layout.updateLayout();
272	    }
273	
274	    /**
275	     * @ch 處理 PLAY_MARK 事件
276	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
277	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
278	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
279	     * EH-9：resolve callback 缺失 → error（caller bug）
280	     */
281	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
282	        if (typeof resolve !== 'function') {
283	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
284	            return;
285	        }
286	        const items = this.GetItemsByBaseSymbol(baseSymbol);
287	        if (items.length === 0) {
288	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
289	            resolve();
290	            return;
291	        }
292	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
293	    }
294	
295	    /**
296	     * @ch 處理 PLAY_MARK_ACTIVE 事件
297	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
298	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
299	     * EH-9：resolve callback 缺失 → error
300	     */
301	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
302	        if (typeof resolve !== 'function') {
303	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
304	            return;
305	        }
306	        const items = this.GetItemsByBaseSymbol(baseSymbol);
307	        if (items.length === 0) {
308	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
309	            resolve();
310	            return;
311	        }
312	        // ── 同步段（Promise.all 之前）：先清本批綁定。並行的其他 dispatch（WantedPosterState 跨 group）
313	        //    也各自同步清，故動畫完成時的 ghost 判定能看到「本波所有離場者皆已退」（§5.5 race 修正）
314	        for (const item of items) {
315	            const idx = this.m_wantedPosterItems.indexOf(item);
316	            if (idx >= 0) this.m_currentBounty[idx] = null;
317	            item.ClearBaseSymbol();
318	        }
319	        // ── 非同步段：動畫播完才切換視覺。判定移到 .then（此時全波同步段已執行完）：
320	        //    仍有 real（survivor 留場）→ 轉 ghost 撐位讓 survivor 不 snap；否則真消失（BC-G6）
321	        Promise.all(items.map(item =>
322	            item.PlayMarkActive().then(() => {
323	                if (this.m_currentBounty.some(b => b !== null)) item.SetContentVisible(false);
324	                else item.node.active = false;
325	            })
326	        )).then(() => {
327	            // 本波後若全場無 real → 釋放殘留 ghost（避免上一輪保留的 ghost 隱形殘留 · §5.3.1）
328	            if (!this.m_currentBounty.some(b => b !== null)) this.NormalizeGhosts();
329	            resolve();
330	        });
331	    }
332	
333	    /**
334	     * @ch 處理 GAME_INTRO_COMPLETE 事件
335	     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）為「已定位」靜止畫面（不播 In 進場）。
336	     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
337	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
338	     */
339	    private HandleGameIntroComplete() {
340	        // Wanted_On 幀事件偏早 + 改走 ShowInSettled（瞬間定位、不播進場）少了原進場的時間差 → 懸賞令早出現約 0.15 秒。
341	        // ⚠️ 暫時方案：時序真相本應落在 spine 的 Wanted_On keyframe；待能改 spine 原檔後移除此延遲。
342	        // 延遲綁在 WantedPosterManager（持久 UI 管理器，node 全程 active），而非 sender GameIntroManager
343	        //（其 node 於 intro 結束 active=false，scheduleOnce 會被取消導致懸賞令不顯示）。
344	        this.scheduleOnce(() => this.ShowGameIntroPoster(), WantedPosterManager.GAME_INTRO_SHOW_DELAY);
345	    }
346	
347	    /**
348	     * @ch 實際顯示 GAME_INTRO_COMPLETE 懸賞令 x9999（由 HandleGameIntroComplete 延遲呼叫）
349	     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
350	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
351	     */
352	    private ShowGameIntroPoster() {
353	        this.EnsureCurrentBountySize();
354	        this.NormalizeGhosts();   // 防禦：0→1 前確保無殘留 ghost（正常此路徑場上為空）
355	        const item = this.m_wantedPosterItems[0];
356	        if (!item) {
357	            warn('[WantedPosterManager] GAME_INTRO_COMPLETE: 懸賞令物品[0] 未設置');
358	            return;
359	        }
360	        const data: IBountyData = { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 };
361	        // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
362	        item.node.active = true;
363	        item.SetWantedPosterData(data);
364	        item.ShowInSettled();           // 直接顯示 In 定位完成的靜止畫面（不播進場）
365	        this.m_currentBounty[0] = data;
366	    }
367	    //#endregion Event Management
368	
369	    //#region Methods
370	    /**
371	     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
372	     *
373	     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
374	     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
375	     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
376	     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
377	     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
378	     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
379	     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
380	     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
381	     *
382	     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
383	     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
384	     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
385	     */
386	    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
387	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
388	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
389	            return;
390	        }
391	        this.EnsureCurrentBountySize();
392	
393	        const count = this.m_wantedPosterItems.length;
394	        // 本輪要顯示的 bounty（Multiple>0 且 BaseSymbol 非 Wanted_Empty 佔位），超量截斷至 item 數量上限
395	        // BaseSymbol === Wanted_Empty 視同空資料（懸賞海報空位），一併排除不顯示
396	        const newBounties = dataList.filter(d => d && d.Multiple > 0 && d.BaseSymbol !== Symbol.Wanted_Empty);
397	        if (newBounties.length > count) {
398	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
399	                newBounties.length, '>', count);
400	            newBounties.length = count;
401	        }
402	
403	        if (isNewRound) {
404	            this.RebuildAll(newBounties);
405	        } else {
406	            this.ReconcileCascade(newBounties, visibleBaseSymbols);
407	        }
408	    }
409	
410	    /**
411	     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
412	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
413	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
414	     */
415	    private RebuildAll(newBounties: IBountyData[]) {
416	        // 整批重建前先釋放殘留 ghost：使下方以 node.active 判退場的迴圈不被 ghost（active 但隱形）干擾（BC-G4 · D5）
417	        this.NormalizeGhosts();
418	        const count = this.m_wantedPosterItems.length;
419	
420	        const outPromises: Promise<void>[] = [];
421	        for (let i = 0; i < count; i++) {
422	            const item = this.m_wantedPosterItems[i];
423	            if (item && item.node.active) {
424	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
425	            }
426	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
427	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
428	        }
429	
430	        const enterAll = () => {
431	            for (let i = 0; i < newBounties.length; i++) {
432	                const item = this.m_wantedPosterItems[i];
433	                if (!item) continue;
434	                // 先 active 再 ShowContent 再 setSkin：inactive/Content off 時 setSkin 不重建 render data（殘留舊 skin）
435	                item.node.active = true;
436	                item.SetContentVisible(true);
437	                item.SetWantedPosterData(newBounties[i]);
438	                item.PlayIn();
439	            }
440	        };
441	
442	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
443	        else enterAll();
444	    }
445	
446	    /**
447	     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
448	     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
449	     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
450	     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
451	     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
452	     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
453	     */
454	    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
455	        const count = this.m_wantedPosterItems.length;
456	        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;
457	
458	        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
459	        const pool = new Map<number, IBountyData[]>();
460	        for (const b of newBounties) {
461	            const list = pool.get(b.BaseSymbol);
462	            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
463	        }
464	
465	        const preFreeSlots: number[] = [];      // 更新前就空著的 item（含 pre-existing ghost），供進場立即 reuse
466	        const vacatingSlots: number[] = [];     // 本輪「真消失」騰出的 item，Out 完才可用
467	        const outPromises: Promise<void>[] = [];
468	        const deferredEnter: IBountyData[] = [];
469	        const leavingSlots: number[] = [];      // BC-22 離場者：ghost vs 真消失待 Pass A 後依 hasSurvivor 決定
470	        let hasSurvivor = false;                // 任一 BC-25 持續者（全程沒播 Out/In）→ 需 ghost 撐位防 snap
471	
472	        // Pass A：逐一決定目前已綁定 item 的命運（BC-22 離場決策延後到收尾）
473	        for (let i = 0; i < count; i++) {
474	            const cur = this.m_currentBounty[i];
475	            const item = this.m_wantedPosterItems[i];
476	            if (cur === null) {
477	                if (item) preFreeSlots.push(i);              // 空格或 pre-existing ghost（皆可被新進場 reuse）
478	                continue;
479	            }
480	            const bs = cur.BaseSymbol;
481	            const list = pool.get(bs);
482	            if (list && list.length > 0) {
483	                const onBoard = visible ? visible.has(bs) : true;
484	                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
485	                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
486	                if (sameIdx >= 0) {
487	                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
488	                    hasSurvivor = true;                      // 連續顯示者，被搬動會被察覺 → 需 ghost 撐位
489	                } else {
490	                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場（有 In 動畫遮蓋，不算 survivor）
491	                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
492	                    this.m_currentBounty[i] = nb;
493	                }
494	                if (list.length === 0) pool.delete(bs);
495	            } else {
496	                leavingSlots.push(i);                        // BC-22 離場：ghost/gone 待收尾決策
497	            }
498	        }
499	
500	        // Pass A 收尾：依 hasSurvivor 對離場者統一決策（ghost 撐位 vs 真消失）
501	        for (const i of leavingSlots) {
502	            const item = this.m_wantedPosterItems[i];
503	            this.m_currentBounty[i] = null;
504	            if (hasSurvivor) {
505	                // BC-G1 轉 ghost：item root 維持 active 撐住 Layout 版位，讓 BC-25 持續者不 snap
506	                if (item) {
507	                    item.ClearBaseSymbol();
508	                    outPromises.push(item.PlayOut().then(() => { item.SetContentVisible(false); }));
509	                }
510	            } else {
511	                // 真消失：無連續 survivor 需保護
512	                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
513	                vacatingSlots.push(i);
514	            }
515	        }
516	
517	        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
518	        const remaining: IBountyData[] = [];
519	        for (const list of pool.values()) remaining.push(...list);
520	        for (const nb of remaining) {
521	            if (preFreeSlots.length > 0) {
522	                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位/pre-existing ghost → 立即 reuse 進場
523	            } else {
524	                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
525	            }
526	        }
527	
528	        // 收尾：deferredEnter 等退場騰位 + postReal===0 釋放殘留 ghost（§5.3.1）
529	        // NormalizeGhosts 只釋放「active 且綁定 null」者；先 enter 後 normalize，EnterAt 已填綁定的格不受影響
530	        const needReleaseLingering = !this.m_currentBounty.some(b => b !== null);
531	        if (deferredEnter.length > 0 || needReleaseLingering) {
532	            Promise.all(outPromises).then(() => {
533	                for (const nb of deferredEnter) {
534	                    const idx = vacatingSlots.shift();
535	                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
536	                    this.EnterAt(idx, nb);
537	                }
538	                if (needReleaseLingering) this.NormalizeGhosts();
539	            });
540	        }
541	    }
542	
543	    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
544	    private EnterAt(index: number, data: IBountyData) {
545	        const item = this.m_wantedPosterItems[index];
546	        if (!item) return;
547	        // 先 active 再 ShowContent 再 setSkin：reuse ghost 格時 Content 仍 off，須先開可見，
548	        // 否則 inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
549	        item.node.active = true;
550	        item.SetContentVisible(true);
551	        item.SetWantedPosterData(data);
552	        item.PlayIn();
553	        this.m_currentBounty[index] = data;
554	    }
555	
556	    /**
557	     * @ch 釋放所有 ghost（node.active 但綁定為 null）→ 還原為真消失 + Content 預設可見。
558	     * 用於：RebuildAll / HandleGameIntroComplete 起手（整批前清殘留，使 node.active 判定不被 ghost 干擾）、
559	     *       ReconcileCascade / HandlePlayMarkActive 退到全空時（避免上一輪保留的 ghost 隱形殘留 · BC-G4）。
560	     */
561	    private NormalizeGhosts() {
562	        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
563	            const item = this.m_wantedPosterItems[i];
564	            if (item && item.node.active && this.m_currentBounty[i] === null) {
565	                item.node.active = false;
566	                item.SetContentVisible(true);   // 還原 Content 預設態，供下次進場
567	                item.ClearBaseSymbol();
568	            }
569	        }
570	    }
571	
572	    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
573	    private EnsureCurrentBountySize() {
574	        const count = this.m_wantedPosterItems.length;
575	        if (this.m_currentBounty.length === count) return;
576	        const next: (IBountyData | null)[] = new Array(count).fill(null);
577	        const keep = Math.min(this.m_currentBounty.length, count);
578	        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
579	        this.m_currentBounty = next;
580	    }
581	
582	    /**
583	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
584	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
585	     */
586	    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
587	        if (baseSymbol === null || baseSymbol === undefined) return [];
588	        const result: WantedPosterItem[] = [];
589	        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
590	            const item = this.m_wantedPosterItems[i];
591	            const cur = this.m_currentBounty[i];
592	            // 用 m_currentBounty 判斷「正在顯示真懸賞令」，排除 ghost（node.active 但綁定為 null）
593	            // — ghost 的 GetBaseSymbol() 已 ClearBaseSymbol 為 MAX，但以綁定為準更直接（BC-G5）
594	            if (item && item.node.active && cur !== null && cur.BaseSymbol === baseSymbol) {
595	                result.push(item);
596	            }
597	        }
598	        return result;
599	    }
600	    /**
601	     * @ch 設置懸賞令 UI 顯示狀態
602	     * @param isShow 是否顯示
603	     */
604	    private SetWantedPosterUIShow(isShow: boolean) {
605	        if (!this.m_rootNode) {
606	            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
607	            return;
608	        }
609	        this.m_rootNode.active = isShow;
610	    }
611	    //#endregion Methods
612	
613	    //#region 測試功能
614	    /**
615	     * @ch 測試按鍵處理
616	     * - 數字鍵 1：顯示 1 個懸賞令
617	     * - 數字鍵 2：顯示 2 個懸賞令
618	     * - 數字鍵 3：顯示 UI
619	     * - 數字鍵 4：隱藏 UI
620	     */
621	    private CheckTestKeyCode(event: EventKeyboard): void {
622	        if (!DEBUG) return;
623	        switch (event.keyCode) {
624	            case KeyCode.DIGIT_1:
625	                // 測試：顯示 1 個懸賞令
626	                this.SetWantedPosterData([
627	                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
628	                ], true);
629	                break;
630	
631	            case KeyCode.DIGIT_2:
632	                // 測試：顯示 2 個懸賞令
633	                this.SetWantedPosterData([
634	                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
635	                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
636	                ], true);
637	                break;
638	
639	            case KeyCode.DIGIT_3:
640	                // 測試：顯示 UI
641	                this.SetWantedPosterUIShow(true);
642	                break;
643	
644	            case KeyCode.DIGIT_4:
645	                // 測試：隱藏 UI
646	                this.SetWantedPosterUIShow(false);
647	                break;
648	        }
649	    }
650	    //#endregion 測試功能
651	}
652	
