import { _decorator, Component, Enum, EventKeyboard, Input, input, KeyCode, Layout, log, Node, warn } from 'cc';
import { DEBUG } from 'cc/env';
import { eventManager } from 'db://astarte-framework/Managers';
import { Common } from '../Common/Common';
import { Symbol, IBountyData, GAME_EVENT } from '../Game_Define';
import { WantedPosterItem } from './WantedPosterItem';
const { ccclass, property } = _decorator;

/**@ch 懸賞令排版方向設定（直/橫各一組）*/
@ccclass('WantedPosterLayoutConfig')
class WantedPosterLayoutConfig {
    @property({ type: Enum(Layout.Type), tooltip: "排版類型" })
    type = Layout.Type.VERTICAL;

    @property({ type: Enum(Layout.ResizeMode), tooltip: "縮放模式" })
    resizeMode = Layout.ResizeMode.NONE;

    @property({ tooltip: "左內距" }) paddingLeft: number = 0;
    @property({ tooltip: "右內距" }) paddingRight: number = 0;
    @property({ tooltip: "上內距" }) paddingTop: number = 0;
    @property({ tooltip: "下內距" }) paddingBottom: number = 0;
    @property({ tooltip: "水平間距" }) spacingX: number = 0;
    @property({ tooltip: "垂直間距" }) spacingY: number = 0;
    @property({ tooltip: "水平對齊（GRID 模式有效）" }) alignHorizontal: boolean = false;
    @property({ tooltip: "垂直對齊（GRID 模式有效）" }) alignVertical: boolean = false;
}

/**@ch 懸賞令管理器事件*/
export const WANTED_POSTER_MANAGER_EVENT = {
    /**
     * @ch 設置懸賞令資料
     * @param IBountyData[] 懸賞令資料陣列
     */
    SET_WANTED_POSTER_DATA: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_DATA",

    /**
     * @ch 設置懸賞令UI顯示狀態
     * @param isShow 是否顯示
     */
    SET_WANTED_POSTER_UI_SHOW: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_UI_SHOW",

    /**
     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark → Mark_Idle loop
     * @param baseSymbol number 對應的 BaseSymbol（M1~M9）
     * @param resolve () => void 播完 Mark 後呼叫（Mark_Idle 已在 spine 上 loop）
     */
    PLAY_MARK: "WANTED_POSTER_MANAGER_PLAY_MARK",

    /**
     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark_Active 並關閉 item
     * @param baseSymbol number 對應的 BaseSymbol
     * @param resolve () => void 播完 Mark_Active 且 item.active=false 後呼叫
     */
    PLAY_MARK_ACTIVE: "WANTED_POSTER_MANAGER_PLAY_MARK_ACTIVE",

    /**
     * @ch 遊戲介紹完成後顯示懸賞令x9999
     */
    GAME_INTRO_COMPLETE: "WANTED_POSTER_MANAGER_GAME_INTRO_COMPLETE",
}

/**@ch 懸賞令管理器*/
@ccclass('WantedPosterManager')
export class WantedPosterManager extends Component {
    //#region Constants
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
        WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE,
        GAME_EVENT.DEVICE_ROTATION,
    ];

    /**
     * @ch GAME_INTRO_COMPLETE 顯示懸賞令的延遲（秒）
     * 補 intro spine 的 Wanted_On 幀事件偏早約 0.15 秒（暫時方案，待能改 spine 原檔後移除）
     */
    private static readonly GAME_INTRO_SHOW_DELAY = 0.15;
    //#endregion Constants

    //#region Properties
    @property({
        type: Node,
        tooltip: "根節點"
    })
    private m_rootNode: Node = null;

    @property({
        type: [WantedPosterItem],
        tooltip: "懸賞令物品"
    })
    private m_wantedPosterItems: WantedPosterItem[] = [];

    @property({
        type: Layout,
        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
    })
    private m_layout: Layout = null;

    @property({
        type: WantedPosterLayoutConfig,
        tooltip: "直向排版設定"
    })
    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();

    @property({
        type: WantedPosterLayoutConfig,
        tooltip: "橫向排版設定"
    })
    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
    //#endregion Properties

    //#region Variables
    /**@ch 是否已初始化*/
    private m_isInitialized: boolean = false;

    /**
     * @ch 各 item 目前綁定的懸賞令資料（null = 該 item 未顯示）
     * 與 m_wantedPosterItems 同索引，是「同 BaseSymbol 持續判斷」與「倍率是否變」的真實依據
     * （item 本身只記 BaseSymbol、不記 Multiple，故由 Manager 統一追蹤）
     */
    private m_currentBounty: (IBountyData | null)[] = [];
    //#endregion Variables

    //#region Lifecycle
    /**@ch 元件載入時調用*/
    onLoad() {
        this.RegisterEvent();
        this.RegisterKeyboardEvents();
        this.EnsureCurrentBountySize();
    }

    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
    start() {
        this.ApplyLayoutByOrientation();
    }

    /**@ch 元件銷毀時調用*/
    onDestroy() {
        if (!this.m_isInitialized) return;
        this.UnregisterEvent();
        this.UnregisterKeyboardEvents();
        this.m_isInitialized = false;
    }
    //#endregion Lifecycle

    //#region Event Management
    /**@ch 註冊鍵盤事件（測試用）*/
    private RegisterKeyboardEvents(): void {
        if (!DEBUG) return;
        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**@ch 取消註冊鍵盤事件（測試用）*/
    private UnregisterKeyboardEvents(): void {
        if (!DEBUG) return;
        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**@ch 註冊事件*/
    private RegisterEvent() {
        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });
        this.m_isInitialized = true;
    }

    /**@ch 取消註冊事件*/
    private UnregisterEvent() {
        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });
    }

    /**
     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
        if (typeof args[0] !== 'boolean') {
            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
        if (!Array.isArray(args[0])) {
            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
            return false;
        }
        return true;
    }

    /**
     * @ch 事件回調
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
                if (this.ValidateSetWantedPosterDataArgs(args)) {
                    this.SetWantedPosterData(
                        args[0] as IBountyData[],
                        args[1] === true,
                        Array.isArray(args[2]) ? args[2] as number[] : undefined
                    );
                }
                break;

            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
                    this.SetWantedPosterUIShow(args[0] as boolean);
                }
                break;

            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
                this.HandlePlayMark(args[0] as number, args[1] as () => void);
                break;

            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
                break;

            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
                this.HandleGameIntroComplete();
                break;

            case GAME_EVENT.DEVICE_ROTATION:
                this.ApplyLayoutByOrientation();
                break;

            default:
                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
        }
    }

    /**
     * @ch 依目前裝置方向套用對應的 Layout 設定
     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
     */
    private ApplyLayoutByOrientation(): void {
        if (!this.m_layout) {
            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
            return;
        }
        const isLandscape = Common.GetGameView().IsLandscape;
        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;

        this.m_layout.type = cfg.type;
        this.m_layout.resizeMode = cfg.resizeMode;
        this.m_layout.paddingLeft = cfg.paddingLeft;
        this.m_layout.paddingRight = cfg.paddingRight;
        this.m_layout.paddingTop = cfg.paddingTop;
        this.m_layout.paddingBottom = cfg.paddingBottom;
        this.m_layout.spacingX = cfg.spacingX;
        this.m_layout.spacingY = cfg.spacingY;
        this.m_layout.alignHorizontal = cfg.alignHorizontal;
        this.m_layout.alignVertical = cfg.alignVertical;
        this.m_layout.updateLayout();
    }

    /**
     * @ch 處理 PLAY_MARK 事件
     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
     * EH-9：resolve callback 缺失 → error（caller bug）
     */
    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
        if (typeof resolve !== 'function') {
            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
            return;
        }
        const items = this.GetItemsByBaseSymbol(baseSymbol);
        if (items.length === 0) {
            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
            resolve();
            return;
        }
        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
    }

    /**
     * @ch 處理 PLAY_MARK_ACTIVE 事件
     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
     * EH-9：resolve callback 缺失 → error
     */
    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
        if (typeof resolve !== 'function') {
            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
            return;
        }
        const items = this.GetItemsByBaseSymbol(baseSymbol);
        if (items.length === 0) {
            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
            resolve();
            return;
        }
        // ── 同步段（Promise.all 之前）：先清本批綁定。並行的其他 dispatch（WantedPosterState 跨 group）
        //    也各自同步清，故動畫完成時的 ghost 判定能看到「本波所有離場者皆已退」（§5.5 race 修正）
        for (const item of items) {
            const idx = this.m_wantedPosterItems.indexOf(item);
            if (idx >= 0) this.m_currentBounty[idx] = null;
            item.ClearBaseSymbol();
        }
        // ── 非同步段：動畫播完才切換視覺。判定移到 .then（此時全波同步段已執行完）：
        //    仍有 real（survivor 留場）→ 轉 ghost 撐位讓 survivor 不 snap；否則真消失（BC-G6）
        Promise.all(items.map(item =>
            item.PlayMarkActive().then(() => {
                if (this.m_currentBounty.some(b => b !== null)) item.SetContentVisible(false);
                else item.node.active = false;
            })
        )).then(() => {
            // 本波後若全場無 real → 釋放殘留 ghost（避免上一輪保留的 ghost 隱形殘留 · §5.3.1）
            if (!this.m_currentBounty.some(b => b !== null)) this.NormalizeGhosts();
            resolve();
        });
    }

    /**
     * @ch 處理 GAME_INTRO_COMPLETE 事件
     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）為「已定位」靜止畫面（不播 In 進場）。
     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
     */
    private HandleGameIntroComplete() {
        // Wanted_On 幀事件偏早 + 改走 ShowInSettled（瞬間定位、不播進場）少了原進場的時間差 → 懸賞令早出現約 0.15 秒。
        // ⚠️ 暫時方案：時序真相本應落在 spine 的 Wanted_On keyframe；待能改 spine 原檔後移除此延遲。
        // 延遲綁在 WantedPosterManager（持久 UI 管理器，node 全程 active），而非 sender GameIntroManager
        //（其 node 於 intro 結束 active=false，scheduleOnce 會被取消導致懸賞令不顯示）。
        this.scheduleOnce(() => this.ShowGameIntroPoster(), WantedPosterManager.GAME_INTRO_SHOW_DELAY);
    }

    /**
     * @ch 實際顯示 GAME_INTRO_COMPLETE 懸賞令 x9999（由 HandleGameIntroComplete 延遲呼叫）
     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
     */
    private ShowGameIntroPoster() {
        this.EnsureCurrentBountySize();
        this.NormalizeGhosts();   // 防禦：0→1 前確保無殘留 ghost（正常此路徑場上為空）
        const item = this.m_wantedPosterItems[0];
        if (!item) {
            warn('[WantedPosterManager] GAME_INTRO_COMPLETE: 懸賞令物品[0] 未設置');
            return;
        }
        const data: IBountyData = { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 };
        // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
        item.node.active = true;
        item.SetWantedPosterData(data);
        item.ShowInSettled();           // 直接顯示 In 定位完成的靜止畫面（不播進場）
        this.m_currentBounty[0] = data;
    }
    //#endregion Event Management

    //#region Methods
    /**
     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
     *
     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
     *
     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
     */
    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
            return;
        }
        this.EnsureCurrentBountySize();

        const count = this.m_wantedPosterItems.length;
        // 本輪要顯示的 bounty（Multiple>0 且 BaseSymbol 非 Wanted_Empty 佔位），超量截斷至 item 數量上限
        // BaseSymbol === Wanted_Empty 視同空資料（懸賞海報空位），一併排除不顯示
        const newBounties = dataList.filter(d => d && d.Multiple > 0 && d.BaseSymbol !== Symbol.Wanted_Empty);
        if (newBounties.length > count) {
            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
                newBounties.length, '>', count);
            newBounties.length = count;
        }

        if (isNewRound) {
            this.RebuildAll(newBounties);
        } else {
            this.ReconcileCascade(newBounties, visibleBaseSymbols);
        }
    }

    /**
     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
     */
    private RebuildAll(newBounties: IBountyData[]) {
        // 整批重建前先釋放殘留 ghost：使下方以 node.active 判退場的迴圈不被 ghost（active 但隱形）干擾（BC-G4 · D5）
        this.NormalizeGhosts();
        const count = this.m_wantedPosterItems.length;

        const outPromises: Promise<void>[] = [];
        for (let i = 0; i < count; i++) {
            const item = this.m_wantedPosterItems[i];
            if (item && item.node.active) {
                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
            }
            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
        }

        const enterAll = () => {
            for (let i = 0; i < newBounties.length; i++) {
                const item = this.m_wantedPosterItems[i];
                if (!item) continue;
                // 先 active 再 ShowContent 再 setSkin：inactive/Content off 時 setSkin 不重建 render data（殘留舊 skin）
                item.node.active = true;
                item.SetContentVisible(true);
                item.SetWantedPosterData(newBounties[i]);
                item.PlayIn();
            }
        };

        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
        else enterAll();
    }

    /**
     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
     */
    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
        const count = this.m_wantedPosterItems.length;
        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;

        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
        const pool = new Map<number, IBountyData[]>();
        for (const b of newBounties) {
            const list = pool.get(b.BaseSymbol);
            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
        }

        const preFreeSlots: number[] = [];      // 更新前就空著的 item（含 pre-existing ghost），供進場立即 reuse
        const vacatingSlots: number[] = [];     // 本輪「真消失」騰出的 item，Out 完才可用
        const outPromises: Promise<void>[] = [];
        const deferredEnter: IBountyData[] = [];
        const leavingSlots: number[] = [];      // BC-22 離場者：ghost vs 真消失待 Pass A 後依 hasSurvivor 決定
        let hasSurvivor = false;                // 任一 BC-25 持續者（全程沒播 Out/In）→ 需 ghost 撐位防 snap

        // Pass A：逐一決定目前已綁定 item 的命運（BC-22 離場決策延後到收尾）
        for (let i = 0; i < count; i++) {
            const cur = this.m_currentBounty[i];
            const item = this.m_wantedPosterItems[i];
            if (cur === null) {
                if (item) preFreeSlots.push(i);              // 空格或 pre-existing ghost（皆可被新進場 reuse）
                continue;
            }
            const bs = cur.BaseSymbol;
            const list = pool.get(bs);
            if (list && list.length > 0) {
                const onBoard = visible ? visible.has(bs) : true;
                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
                if (sameIdx >= 0) {
                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
                    hasSurvivor = true;                      // 連續顯示者，被搬動會被察覺 → 需 ghost 撐位
                } else {
                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場（有 In 動畫遮蓋，不算 survivor）
                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
                    this.m_currentBounty[i] = nb;
                }
                if (list.length === 0) pool.delete(bs);
            } else {
                leavingSlots.push(i);                        // BC-22 離場：ghost/gone 待收尾決策
            }
        }

        // Pass A 收尾：依 hasSurvivor 對離場者統一決策（ghost 撐位 vs 真消失）
        for (const i of leavingSlots) {
            const item = this.m_wantedPosterItems[i];
            this.m_currentBounty[i] = null;
            if (hasSurvivor) {
                // BC-G1 轉 ghost：item root 維持 active 撐住 Layout 版位，讓 BC-25 持續者不 snap
                if (item) {
                    item.ClearBaseSymbol();
                    outPromises.push(item.PlayOut().then(() => { item.SetContentVisible(false); }));
                }
            } else {
                // 真消失：無連續 survivor 需保護
                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
                vacatingSlots.push(i);
            }
        }

        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
        const remaining: IBountyData[] = [];
        for (const list of pool.values()) remaining.push(...list);
        for (const nb of remaining) {
            if (preFreeSlots.length > 0) {
                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位/pre-existing ghost → 立即 reuse 進場
            } else {
                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
            }
        }

        // 收尾：deferredEnter 等退場騰位 + postReal===0 釋放殘留 ghost（§5.3.1）
        // NormalizeGhosts 只釋放「active 且綁定 null」者；先 enter 後 normalize，EnterAt 已填綁定的格不受影響
        const needReleaseLingering = !this.m_currentBounty.some(b => b !== null);
        if (deferredEnter.length > 0 || needReleaseLingering) {
            Promise.all(outPromises).then(() => {
                for (const nb of deferredEnter) {
                    const idx = vacatingSlots.shift();
                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
                    this.EnterAt(idx, nb);
                }
                if (needReleaseLingering) this.NormalizeGhosts();
            });
        }
    }

    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
    private EnterAt(index: number, data: IBountyData) {
        const item = this.m_wantedPosterItems[index];
        if (!item) return;
        // 先 active 再 ShowContent 再 setSkin：reuse ghost 格時 Content 仍 off，須先開可見，
        // 否則 inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
        item.node.active = true;
        item.SetContentVisible(true);
        item.SetWantedPosterData(data);
        item.PlayIn();
        this.m_currentBounty[index] = data;
    }

    /**
     * @ch 釋放所有 ghost（node.active 但綁定為 null）→ 還原為真消失 + Content 預設可見。
     * 用於：RebuildAll / HandleGameIntroComplete 起手（整批前清殘留，使 node.active 判定不被 ghost 干擾）、
     *       ReconcileCascade / HandlePlayMarkActive 退到全空時（避免上一輪保留的 ghost 隱形殘留 · BC-G4）。
     */
    private NormalizeGhosts() {
        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
            const item = this.m_wantedPosterItems[i];
            if (item && item.node.active && this.m_currentBounty[i] === null) {
                item.node.active = false;
                item.SetContentVisible(true);   // 還原 Content 預設態，供下次進場
                item.ClearBaseSymbol();
            }
        }
    }

    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
    private EnsureCurrentBountySize() {
        const count = this.m_wantedPosterItems.length;
        if (this.m_currentBounty.length === count) return;
        const next: (IBountyData | null)[] = new Array(count).fill(null);
        const keep = Math.min(this.m_currentBounty.length, count);
        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
        this.m_currentBounty = next;
    }

    /**
     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
     */
    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
        if (baseSymbol === null || baseSymbol === undefined) return [];
        const result: WantedPosterItem[] = [];
        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
            const item = this.m_wantedPosterItems[i];
            const cur = this.m_currentBounty[i];
            // 用 m_currentBounty 判斷「正在顯示真懸賞令」，排除 ghost（node.active 但綁定為 null）
            // — ghost 的 GetBaseSymbol() 已 ClearBaseSymbol 為 MAX，但以綁定為準更直接（BC-G5）
            if (item && item.node.active && cur !== null && cur.BaseSymbol === baseSymbol) {
                result.push(item);
            }
        }
        return result;
    }
    /**
     * @ch 設置懸賞令 UI 顯示狀態
     * @param isShow 是否顯示
     */
    private SetWantedPosterUIShow(isShow: boolean) {
        if (!this.m_rootNode) {
            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
            return;
        }
        this.m_rootNode.active = isShow;
    }
    //#endregion Methods

    //#region 測試功能
    /**
     * @ch 測試按鍵處理
     * - 數字鍵 1：顯示 1 個懸賞令
     * - 數字鍵 2：顯示 2 個懸賞令
     * - 數字鍵 3：顯示 UI
     * - 數字鍵 4：隱藏 UI
     */
    private CheckTestKeyCode(event: EventKeyboard): void {
        if (!DEBUG) return;
        switch (event.keyCode) {
            case KeyCode.DIGIT_1:
                // 測試：顯示 1 個懸賞令
                this.SetWantedPosterData([
                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
                ], true);
                break;

            case KeyCode.DIGIT_2:
                // 測試：顯示 2 個懸賞令
                this.SetWantedPosterData([
                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
                ], true);
                break;

            case KeyCode.DIGIT_3:
                // 測試：顯示 UI
                this.SetWantedPosterUIShow(true);
                break;

            case KeyCode.DIGIT_4:
                // 測試：隱藏 UI
                this.SetWantedPosterUIShow(false);
                break;
        }
    }
    //#endregion 測試功能
}

