1	import { log, Node, Vec3, warn } from "cc";
2	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define from "../Game_Define";
5	import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
6	import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
7	import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
8	import { Define } from "db://astarte-framework/utilis";
9	import { AudioManager } from "../Audio/AudioManager";
10	
11	export class WantedPosterState extends BaseState
12	{
13	    private m_gameView: GameView = null;
14	
15	    constructor( gameView: GameView )
16	    {
17	        super();
18	        this.m_gameView = gameView;
19	    }
20	
21	    public async OnEnter()
22	    {
23	
24	        log( "OnEnter State : WANTED_POSTER" );
25	        const plateInfo = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ]
26	            .PlateQueue[ this.m_gameView.CurPlateIndex ];
27	
28	        const awardDataVec = plateInfo.AwardDataVec ?? [];
29	        const bountyDataVec = plateInfo.BountyDataVec ?? [];
30	
31	        // BC-3：找出被消除的符號中，有哪些命中懸賞令的 BaseSymbol
32	        const triggeredBounties = this.FindTriggeredBounties( awardDataVec, bountyDataVec );
33	
34	        if ( triggeredBounties.length === 0 )
35	        {
36	
37	            stateManager.NextState( Game_Define.GameState.MATCHING_PATCH_UP );
38	            return;
39	        }
40	
41	        // 以 BaseSymbol 分組，同組合併成一隻 spine（連乘）
42	        const basePlateIndexes = plateInfo.BasePlateIndex ?? [];
43	        const groups = this.GroupBountiesByBaseSymbol( triggeredBounties );
44	
45	        // 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本狀態只播懸賞令 spine 演出；
46	        // 多個不同 BaseSymbol 群組改為「並行」一起演出（不再逐組序列）。
47	        await Promise.all( groups.map( group => this.PlayBountyGroupPerform(
48	            group, awardDataVec, plateInfo.PlateSymbol, basePlateIndexes
49	        ) ) );
50	
51	        stateManager.NextState( Game_Define.GameState.MATCHING_PATCH_UP );
52	    }
53	
54	    public OnProcess() { }
55	
56	    public OnLeave() { }
57	
58	    /**
59	     * @ch 對「一組同 BaseSymbol 的懸賞」執行 ①Mark → ②Symbol_In → ③(Mark_Active ∥ Symbol_Active) → ④底板SET
60	     *
61	     * 透過 WANTED_POSTER_MANAGER_EVENT 與常駐 WantedPosterManager 溝通；
62	     * 場上 Wanted Spine 由 EffectPlate.SpawnAndPlayWantedSymbolIn / PlayWantedSymbolActiveAndRecycle 直接呼叫
63	     *
64	     * 合併語意：同組所有 bounty 共用同一 BaseSymbol（前提②）與同一組位置
65	     * （同 BaseSymbol → awardDataVec 對應唯一一筆 award），故 spawn 只跑一次。
66	     *
67	     * BC-4：對該 BaseSymbol 的所有常駐 item 同時播 Mark → Mark_Active，最後各自 active=false（Manager.OnEvent 內處理）
68	     * BC-6：階段 ③ Mark_Active 與 Symbol_Active 同 Promise.all 起播
69	     * BC-7：場上 spine 顯示組內 Multiple 連乘（純表演）
70	     * 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本方法不再消除，只播 spine 演出。
71	     * EH-1：找不到對應 item 由 Manager 內部 warn + 立刻 resolve，不阻斷流程
72	     */
73	    private async PlayBountyGroupPerform(
74	        group: protocol.ar2pq9Proto.IBountyData[],
75	        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
76	        curPlateSymbol: protocol.ar2pq9Proto.IColumn[],
77	        basePlateIndexes: protocol.ar2pq9Proto.IIntAry[]
78	    ): Promise<void>
79	    {
80	        if ( group.length === 0 ) return;
81	
82	        // 組內共同 BaseSymbol（前提②：同 BaseSymbol 的 BountySymbol 一定相同）
83	        const baseSymbol = group[ 0 ].BaseSymbol;
84	        if ( baseSymbol === null || baseSymbol === undefined )
85	        {
86	            warn( '[WantedPosterState] PlayBountyGroupPerform: BaseSymbol 為空，跳過' );
87	            return;
88	        }
89	
90	        // 位置由組內共同 BaseSymbol 單次取得（與組內筆數無關）
91	        const matchedAward = awardDataVec.find(
92	            award => award.Symbol === baseSymbol
93	                && award.EliminatePos
94	                && award.EliminatePos.length > 0
95	        );
96	        if ( !matchedAward ) return;
97	
98	        // 過濾掉 Wild 位置（spine 與 ④底板只跑非 wild；wild 的消除/底板已在 ExplodeState 處理）
99	        const filteredPositions = this.FilterNonWildPositions(
100	            matchedAward.EliminatePos!, curPlateSymbol
101	        );
102	        // 無非 wild 位置 → 無 spine 可演（wild 消除已在 ExplodeState 完成）
103	        if ( filteredPositions.length === 0 ) return;
104	
105	        // 場上 spine 顯示倍率 = 組內 Multiple 連乘（純表演）
106	        const multiplier = this.ComputeGroupMultiplier( group );
107	
108	        // 把 positions(一維索引) 轉為世界座標（事件 payload 用世界座標，避免在 manager 跨越 SlotReels 依賴）
109	        const worldPositions = filteredPositions.map( pos => {
110	            const col = Math.floor( pos / Game_Define.ROW );
111	            const row = pos % Game_Define.ROW;
112	            return this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow( col, row );
113	        } );
114	
115	        // ① Mark — 事件 + Promise wrapper（同 EffectPlate 對 MULTIPLIER_BASE_MANAGER 的風格）
116	        await new Promise<void>( resolve => {
117	            eventManager.Dispatch(
118	                WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
119	                baseSymbol,
120	                resolve
121	            );
122	        } );
123	
124	        // ② 懸賞令 spine 進場（Symbol_In）。symbol/wild 消除已在 ExplodeState 步驟①完成，此處不再消除
125	        const spawnedNodes: Node[] = await this.m_gameView.EffectPlate.SpawnAndPlayWantedSymbolIn(
126	            worldPositions, baseSymbol, multiplier
127	        );
128	
129	        // ③ Mark_Active ∥ Symbol_Active 同時起播
130	        await Promise.all( [
131	            new Promise<void>( resolve => {
132	                eventManager.Dispatch(
133	                    WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
134	                    baseSymbol,
135	                    resolve
136	                );
137	            } ),
138	            this.m_gameView.EffectPlate.PlayWantedSymbolActiveAndRecycle( spawnedNodes ),
139	        ] );
140	
141	        // ④ 場上 Wanted 表演完成後，更新懸賞令位置的乘倍底板（帶 Spine 動畫）
142	        // 移到組末才升底板，避免被階段②/③的 Spine 動畫分散視覺焦點
143	        // await Define.Wait( this.m_gameView, 0.5 );
144	        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true );
145	        // 燃燒表演完成後刷新乘倍底板，同時播放刷新倍數音效（每組一次，並發限制避免多組重疊）
146	        AudioManager.Play( AudioManager.AudioClips.Wanted_MultiAdd );
147	        const upgradePromises: Promise<void>[] = [];
148	        for ( const pos of filteredPositions )
149	        {
150	            const col = Math.floor( pos / Game_Define.ROW );
151	            const row = pos % Game_Define.ROW;
152	            upgradePromises.push( new Promise<void>( resolve =>
153	            {
154	                eventManager.Dispatch(
155	                    MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM,
156	                    pos,
157	                    basePlateIndexes[ col ].Data[ row ],
158	                    resolve
159	                );
160	            } ) );
161	        }
162	        await Promise.all( upgradePromises );
163	    }
164	
165	    /**
166	     * @ch BC-1：將已觸發的 bounty 以 BaseSymbol 分組
167	     * 同 BaseSymbol 歸同組；組順序依各 BaseSymbol 首次出現順序，組內保留原順序。
168	     * 輸入契約：吃 FindTriggeredBounties 的輸出（已觸發子集），非原始 bountyDataVec。
169	     */
170	    private GroupBountiesByBaseSymbol(
171	        bounties: protocol.ar2pq9Proto.IBountyData[]
172	    ): protocol.ar2pq9Proto.IBountyData[][]
173	    {
174	        const groups: protocol.ar2pq9Proto.IBountyData[][] = [];
175	        const groupIndexByBaseSymbol = new Map<number, number>();
176	        for ( const bounty of bounties )
177	        {
178	            const key = bounty.BaseSymbol;
179	            if ( key === null || key === undefined ) continue;
180	            const existing = groupIndexByBaseSymbol.get( key );
181	            if ( existing !== undefined )
182	            {
183	                groups[ existing ].push( bounty );
184	            }
