/**
 * @ch 處理 PLAY_OUT_ALL 事件：全部懸賞令早退場（新一局舊盤掉出時觸發）
 * 同步清空綁定（清後 GetItemsByBaseSymbol 等立即視為空場），對每個 active item 播 Out，
 * 播完還原為乾淨態（active=false + Content 預設可見 + 清 BaseSymbol，比照 NormalizeGhosts）。
 * fire-and-forget：不回 resolve、不阻斷掉出節奏；退場動畫與舊盤掉出各自並行。
 * ⚠️ 前提假設：Out 動畫時長 << 舊盤掉出(~1.5s)+大獎預告。稍後 SetNowRoundInfo 的 RebuildAll
 *    跑到時 item 已 active=false，其 PlayOut 迴圈自然 no-op、只跑新的 PlayIn（沿用 RebuildAll 既有假設）。
 */
private HandlePlayOutAll() {
    this.EnsureCurrentBountySize();
    this.NormalizeGhosts();   // 先釋放 ghost（active 但綁定 null）→ active=false，避免其被當成需退場的 real
    for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
        const item = this.m_wantedPosterItems[i];
        if (item && item.node.active) {
            this.m_currentBounty[i] = null;   // 同步清綁定（本波退場後場上視為空）
            item.PlayOut().then(() => {
                item.node.active = false;
                item.SetContentVisible(true);   // 還原 Content 預設態，供下次進場
                item.ClearBaseSymbol();
            });
        }
    }
}
//#endregion Event Management

